/* ═══════════════════════════════════════════════════════════
   Upload Template Tab
   ═══════════════════════════════════════════════════════════ */
function UploadTemplateTab({ objects, gridData, onGridImported }) {
  const fileInputRef                    = useRef(null);
  const [dragging, setDragging]         = useState(false);
  const [uploading, setUploading]       = useState(false);
  const [uploadResult, setUploadResult] = useState(null);
  const [uploadError, setUploadError]   = useState('');

  const handleFile = async (file) => {
    if (!file) return;
    const ext = file.name.split('.').pop().toLowerCase();
    if (!['xlsx', 'xls'].includes(ext)) {
      setUploadError('Please upload an .xlsx or .xls file.');
      return;
    }
    setUploading(true);
    setUploadError('');
    setUploadResult(null);
    try {
      const { updatedGrid, warnings, totalImported, totalAdded } =
        await parseUploadedExcel(file, objects, gridData);
      onGridImported(updatedGrid);
      setUploadResult({ success: true, warnings, fileName: file.name, totalImported, totalAdded });
    } catch (err) {
      setUploadError(err.message);
    } finally {
      setUploading(false);
    }
  };

  const onFileInputChange = (e) => {
    handleFile(e.target.files?.[0]);
    e.target.value = '';
  };

  const onDrop = (e) => {
    e.preventDefault();
    setDragging(false);
    handleFile(e.dataTransfer.files?.[0]);
  };

  const ratingColors = ['#64748b', '#b45309', '#1d4ed8', '#5b2d90', '#0f766e'];

  return (
    <div style={{ padding: '1.5rem' }}>

      {/* Step 1 */}
      <div style={{ background: '#f9f8fc', border: '1.5px solid #e8e2f5', borderRadius: 10,
        padding: '0.8rem 1.1rem', marginBottom: '1rem' }}>
        <span style={{ fontSize: '0.88rem', fontWeight: 700, color: '#3b1f72' }}>Step 1: </span>
        <span style={{ fontSize: '0.85rem', color: '#555' }}>
          Download the template — it includes all current questions and your object columns
        </span>
      </div>

      <div style={{ textAlign: 'center', marginBottom: '1.6rem' }}>
        <button
          onClick={() => downloadTemplate(gridData, objects)}
          style={{
            display: 'inline-flex', alignItems: 'center', gap: '0.5rem',
            padding: '0.65rem 1.8rem', borderRadius: 999,
            border: '2px solid #5b2d90', background: '#fff',
            color: '#5b2d90', fontWeight: 700, fontSize: '0.9rem',
            cursor: 'pointer', fontFamily: 'inherit', transition: 'all 0.15s',
          }}
          onMouseEnter={e => { e.currentTarget.style.background = '#5b2d90'; e.currentTarget.style.color = '#fff'; }}
          onMouseLeave={e => { e.currentTarget.style.background = '#fff'; e.currentTarget.style.color = '#5b2d90'; }}
        >
          ⬇ Download Excel Template
        </button>
        <p style={{ fontSize: '0.76rem', color: '#9580b8', marginTop: '0.4rem', marginBottom: 0 }}>
          Objects included: <strong>{objects.join(', ')}</strong>
        </p>
      </div>

      {/* Step 2 */}
      <div style={{ background: '#f9f8fc', border: '1.5px solid #e8e2f5', borderRadius: 10,
        padding: '0.8rem 1.1rem', marginBottom: '1rem' }}>
        <span style={{ fontSize: '0.88rem', fontWeight: 700, color: '#3b1f72' }}>Step 2: </span>
        <span style={{ fontSize: '0.85rem', color: '#555' }}>
          Fill ratings in Excel, then upload the completed file — new rows will also be added to the grid
        </span>
      </div>

      {/* Drop zone */}
      <div
        onClick={() => !uploading && fileInputRef.current?.click()}
        onDragOver={e => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onDrop={onDrop}
        style={{
          border: `2.5px dashed ${dragging ? '#5b2d90' : '#d9cef0'}`,
          borderRadius: 16, padding: '2.5rem 1.5rem',
          background: dragging ? 'linear-gradient(135deg,#ede8f7,#f5f0fc)' : 'linear-gradient(135deg,#f5f0fc,#fdf2f8)',
          cursor: uploading ? 'default' : 'pointer', textAlign: 'center',
          transition: 'all 0.2s', userSelect: 'none',
        }}
      >
        {uploading ? (
          <>
            <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>⏳</div>
            <p style={{ color: '#5b2d90', fontWeight: 600, margin: 0 }}>Parsing file and updating grid…</p>
          </>
        ) : (
          <>
            <div style={{ fontSize: '2.2rem', marginBottom: '0.5rem' }}>📤</div>
            <p style={{ fontSize: '0.92rem', color: '#5b2d90', fontWeight: 700, margin: '0 0 0.3rem' }}>
              Click to upload or drag &amp; drop .xlsx here
            </p>
            <p style={{ fontSize: '0.78rem', color: '#9580b8', margin: 0 }}>
              Supports .xlsx and .xls files
            </p>
          </>
        )}
        <input ref={fileInputRef} type="file" accept=".xlsx,.xls"
          onChange={onFileInputChange} style={{ display: 'none' }} />
      </div>

      {/* Error */}
      {uploadError && (
        <div style={{ marginTop: '1rem', background: '#fef2f2', border: '1.5px solid #fca5a5',
          borderRadius: 10, padding: '0.75rem 1rem', color: '#dc2626', fontSize: '0.84rem', fontWeight: 600 }}>
          ⚠️ {uploadError}
          <button onClick={() => setUploadError('')}
            style={{ float: 'right', background: 'none', border: 'none',
              cursor: 'pointer', color: '#dc2626', fontWeight: 700, fontSize: '1rem' }}>✕</button>
        </div>
      )}

      {/* Success */}
      {uploadResult?.success && (
        <div style={{ marginTop: '1rem', background: '#f0fdf4', border: '1.5px solid #86efac',
          borderRadius: 10, padding: '0.85rem 1rem' }}>
          <div style={{ color: '#16a34a', fontWeight: 700, fontSize: '0.9rem', marginBottom: '0.3rem' }}>
            ✅ Successfully imported: <em>{uploadResult.fileName}</em>
          </div>
          <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', marginBottom: '0.3rem' }}>
            <span style={{ background: '#dcfce7', color: '#15803d', fontSize: '0.8rem',
              fontWeight: 700, padding: '2px 10px', borderRadius: 999 }}>
              {uploadResult.totalImported} ratings updated
            </span>
            {uploadResult.totalAdded > 0 && (
              <span style={{ background: '#dbeafe', color: '#1d4ed8', fontSize: '0.8rem',
                fontWeight: 700, padding: '2px 10px', borderRadius: 999 }}>
                {uploadResult.totalAdded} new row{uploadResult.totalAdded !== 1 ? 's' : ''} added
              </span>
            )}
          </div>
          <div style={{ color: '#15803d', fontSize: '0.82rem' }}>
            Grid updated — switching to <strong>Manual Entry</strong> so you can review the changes.
          </div>
          {uploadResult.warnings.length > 0 && (
            <div style={{ marginTop: '0.6rem', background: '#fffbeb', border: '1px solid #fde68a',
              borderRadius: 8, padding: '0.5rem 0.8rem' }}>
              <div style={{ color: '#92400e', fontWeight: 700, fontSize: '0.8rem', marginBottom: '0.25rem' }}>
                ⚠ {uploadResult.warnings.length} warning{uploadResult.warnings.length !== 1 ? 's' : ''}:
              </div>
              {uploadResult.warnings.map((w, i) => (
                <div key={i} style={{ color: '#92400e', fontSize: '0.78rem' }}>• {w}</div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Rating reference card */}
      <div style={{ marginTop: '1.2rem', background: '#f9f8fc', border: '1px solid #e8e2f5',
        borderRadius: 10, padding: '0.75rem 1rem', fontSize: '0.78rem', color: '#7a7a9a' }}>
        <strong style={{ color: '#3b1f72', display: 'block', marginBottom: '0.3rem' }}>
          Valid rating values (case-insensitive):
        </strong>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
          {RATING_LABELS.map((r, i) => (
            <span key={r} style={{ background: '#fff', border: `1.5px solid ${ratingColors[i]}`,
              color: ratingColors[i], fontWeight: 700, padding: '2px 10px', borderRadius: 999, fontSize: '0.78rem' }}>
              {i + 1} = {r}
            </span>
          ))}
        </div>
        <div style={{ marginTop: '0.5rem', color: '#9580b8', fontSize: '0.76rem' }}>
          💡 Tip: You can also add new rows to any sheet — they will appear as new questions in the grid.
        </div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════════════════════ */
export default function MaturityPage({ onNavigate, sessionId, dqScore }) {
  const [clientName, setClientName]               = useState('');
  const [objects, setObjects]                     = useState([...DEFAULT_OBJECTS]);
  const [mastersApplicable, setMastersApplicable] = useState(true);
  const [benchmark, setBenchmark]                 = useState(3.0);
  const [target, setTarget]                       = useState(3.0);
  const [lowThr, setLowThr]                       = useState(2.0);

  const [gridData, setGridData]   = useState(() => buildGridData(QUESTION_BANK, DEFAULT_OBJECTS));
  const [activeDim, setActiveDim] = useState(DIMS_LIST[0]);
  const [fullView, setFullView]   = useState({});
  const [entryTab, setEntryTab]   = useState('manual');

  const [loading, setLoading]     = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [results, setResults]     = useState(null);
  const [error, setError]         = useState('');
  const [apiStatus, setApiStatus] = useState('offline');

  const currentObjects = mastersApplicable ? objects : [clientName || 'Overall'];

  useEffect(() => {
    (async () => {
      try {
        const resp = await getMaturityQuestions([], []);
        if (resp.data.questions && Object.keys(resp.data.questions).length > 0) setApiStatus('connected');
      } catch { setApiStatus('offline'); }
    })();
  }, []);

  useEffect(() => {
    setGridData(prev => {
      const u = { ...prev };
      Object.keys(u).forEach(dim => {
        u[dim] = u[dim].map(row => {
          const nr = { ...row };
          currentObjects.forEach(obj => { if (!(obj in nr)) nr[obj] = RATING_LABELS[0]; });
          return nr;
        });
      });
      return u;
    });
  }, [currentObjects.join(',')]);

  const handleCellChange = useCallback((dim, rowIdx, obj, value) => {
    setGridData(prev => {
      const u    = { ...prev };
      const rows = [...u[dim]];
      rows[rowIdx] = { ...rows[rowIdx], [obj]: value };
      u[dim] = rows;
      return u;
    });
  }, []);

  const addQuestion = (dim) => {
    setGridData(prev => {
      const u  = { ...prev };
      const nr = { id: `CQ-${(u[dim] || []).length + 1}`, section: 'Custom', question: 'Enter question text…', weight: 1 };
      currentObjects.forEach(obj => { nr[obj] = RATING_LABELS[0]; });
      u[dim] = [...(u[dim] || []), nr];
      return u;
    });
  };

  const removeLast = (dim) => {
    setGridData(prev => {
      const u = { ...prev };
      if ((u[dim] || []).length > 1) u[dim] = u[dim].slice(0, -1);
      return u;
    });
  };

  const countFilled = (dim) => {
    let filled = 0, total = 0;
    (gridData[dim] || []).forEach(r => {
      currentObjects.forEach(obj => {
        total++;
        if (r[obj] && r[obj] !== RATING_LABELS[0]) filled++;
      });
    });
    return { filled, total };
  };

  const buildResponsePayload = () => {
    const payload = {};
    DIMS_LIST.forEach(dim => {
      payload[dim] = (gridData[dim] || []).map(row => {
        const r = { Question: row.question, 'Question ID': row.id, Section: row.section, Weight: row.weight };
        currentObjects.forEach(obj => {
          const idx = RATING_LABELS.indexOf(row[obj] || RATING_LABELS[0]);
          r[obj] = String(idx >= 0 ? idx + 1 : 1);
        });
        return r;
      });
    });
    return payload;
  };

  const handleSubmit = async () => {
    if (!clientName.trim()) { setError('Please enter a Client Name.'); return; }
    setLoading(true); setError('');
    try {
      const resp = await submitMaturity({
        session_id: sessionId, client_name: clientName, dims: DIMS_LIST,
        objects: currentObjects, responses: buildResponsePayload(),
        benchmark, target, low_thr: lowThr, dq_score: dqScore,
      });
      setResults(resp.data); setSubmitted(true);
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally { setLoading(false); }
  };

  // Import from upload → merge grid → switch to manual tab so user sees the data
  const handleGridImported = useCallback((updatedGrid) => {
    setGridData(updatedGrid);
    // Small delay so the success banner is visible before tab switches
    setTimeout(() => setEntryTab('manual'), 1200);
  }, []);

  const tp = DIMS_LIST.reduce(
    (a, d) => { const c = countFilled(d); return { filled: a.filled + c.filled, total: a.total + c.total }; },
    { filled: 0, total: 0 }
  );

  /* ─── RENDER ─── */
  return (
    <div className="page-maturity">
      <PageBanner icon="📈" badge="DAMA Framework" title="Data Maturity Assessment"
        subtitle="Evaluate maturity across DAMA dimensions — governance, quality, architecture, integration & privacy — with weighted scoring and benchmarking." />
      <NavPills current="maturity" onChange={onNavigate} />

      {loading && <Spinner message="Computing scores and building reports..." />}
      {error && (
        <div className="error-banner" onClick={() => setError('')} style={{ cursor: 'pointer' }}>
          ⚠️ {error} <span style={{ float: 'right', fontWeight: 700 }}>✕</span>
        </div>
      )}

      {/* ════════ RESULTS ════════ */}
      {submitted && results && !loading && (
        <div className="maturity-results">
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '0.5rem' }}>
            <button className="btn-primary" onClick={() => { setSubmitted(false); setResults(null); }}>✏️ Edit Responses</button>
          </div>

          {dqScore != null && (
            <div className="dq-score-banner">
              <strong>DQ Score:</strong> {dqScore.toFixed(1)}% → <strong>Level:</strong> {results.dq_maturity_level}
            </div>
          )}

          <h3 className="subsection-title">📊 Summary Slide</h3>
          {results.slide_png_b64 && (
            <div className="slide-wrap">
              <img src={`data:image/png;base64,${results.slide_png_b64}`} alt="Summary" style={{ width: '100%', borderRadius: 14 }} />
            </div>
          )}

          {results.dim_table && (
            <div style={{ background: '#fff', border: '1.5px solid #d9cef0', borderRadius: 16,
              padding: '1.2rem 1.4rem 1rem', margin: '1.2rem 0', boxShadow: '0 2px 12px rgba(91,45,144,0.07)' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '0.75rem',
                paddingBottom: '0.5rem', borderBottom: '2px solid #ede8f7' }}>📐 Dimension-wise Maturity</div>
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
                  <thead>
                    <tr>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'left', fontSize: '0.82rem', fontWeight: 700 }}></th>
                      {currentObjects.map(obj => (
                        <th key={obj} style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 0.8rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>{obj}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(results.dim_table).map(([dim, vals], ri) => (
                      <tr key={dim} style={{ background: ri % 2 === 0 ? '#fff' : '#ede8f7' }}>
                        <td style={{ padding: '0.55rem 1rem', fontWeight: 600, color: '#1a1a2e', fontSize: '0.84rem' }}>{dim}</td>
                        {currentObjects.map(obj => {
                          const num = typeof vals[obj] === 'number' ? vals[obj] : parseFloat(vals[obj]) || 0;
                          const bg  = num >= 4 ? '#dcfce7' : num >= 3 ? '#dbeafe' : num >= 2 ? '#fef3c7' : '#fff';
                          return <td key={obj} style={{ padding: '0.55rem 0.8rem', textAlign: 'center', fontWeight: 700, fontSize: '0.9rem', color: '#1a1a2e', background: bg }}>{num.toFixed(2)}</td>;
                        })}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {results.overall && (
            <div style={{ background: '#fff', border: '1.5px solid #d9cef0', borderRadius: 16,
              padding: '1.2rem 1.4rem 1rem', margin: '1.2rem 0', boxShadow: '0 2px 12px rgba(91,45,144,0.07)' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '0.75rem',
                paddingBottom: '0.5rem', borderBottom: '2px solid #ede8f7' }}>🏆 Overall Maturity Score</div>
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
                  <thead>
                    <tr>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>Master Data Object</th>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>Score</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(results.overall).map(([obj, score], ri) => {
                      const num = typeof score === 'number' ? score : parseFloat(score) || 0;
                      return (
                        <tr key={obj} style={{ background: ri % 2 === 0 ? '#fff' : '#ede8f7' }}>
                          <td style={{ padding: '0.55rem 1rem', textAlign: 'center', fontWeight: 600, color: '#1a1a2e', fontSize: '0.84rem' }}>{obj}</td>
                          <td style={{ padding: '0.55rem 1rem', textAlign: 'center', fontWeight: 700, color: '#1a1a2e', fontSize: '0.9rem' }}>{num.toFixed(2)}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {results.domain_scores && (
            <div style={{ background: '#f5f0fc', border: '1.5px solid #d9cef0', borderRadius: 16, padding: '1.4rem 1.6rem', margin: '1.2rem 0' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '1rem' }}>📊 Maturity Bar Chart</div>
              {(() => {
                const barColors = { 1: '#64748b', 2: '#b45309', 3: '#1d4ed8', 4: '#5b2d90', 5: '#0f766e' };
                const getColor  = s => barColors[Math.max(1, Math.min(5, Math.round(s)))] || '#5b2d90';
                return (
                  <div>
                    {Object.entries(results.domain_scores).map(([dim, score]) => {
                      const s = typeof score === 'number' ? score : parseFloat(score) || 1;
                      return (
                        <div key={dim} style={{ display: 'flex', alignItems: 'center', marginBottom: '0.8rem', gap: '0.8rem' }}>
                          <div style={{ width: 250, textAlign: 'right', fontSize: '0.84rem', fontWeight: 600, color: '#0c4a6e', flexShrink: 0 }}>{dim}</div>
                          <div style={{ flex: 1, position: 'relative', height: 28, background: '#e9e4f5', borderRadius: 6, overflow: 'hidden' }}>
                            <div style={{ width: `${Math.min((s / 5) * 100, 100)}%`, height: '100%', background: getColor(s), borderRadius: 6, transition: 'width 0.5s' }} />
                            <div style={{ position: 'absolute', left: '60%', top: 0, bottom: 0, width: 2, background: '#38bdf8', opacity: 0.7 }} />
                            <div style={{ position: 'absolute', left: '80%', top: 0, bottom: 0, width: 2, background: '#0284c7', opacity: 0.7 }} />
                          </div>
                          <div style={{ width: 50, fontWeight: 800, fontSize: '0.95rem', color: '#3d1d63' }}>{s.toFixed(2)}</div>
                        </div>
                      );
                    })}
                    <div style={{ display: 'flex', alignItems: 'center', marginTop: '0.3rem', gap: '0.8rem' }}>
                      <div style={{ width: 250 }} />
                      <div style={{ flex: 1, display: 'flex', justifyContent: 'space-between', fontSize: '0.72rem', color: '#7a7a9a', fontWeight: 600 }}>
                        {[0, 1, 2, 3, 4, 5].map(n => <span key={n}>{n}</span>)}
                      </div>
                      <div style={{ width: 50 }} />
                    </div>
                    <div style={{ textAlign: 'center', fontSize: '0.78rem', fontWeight: 600, color: '#0c4a6e', marginTop: '0.3rem' }}>
                      Maturity Score (1=Adhoc → 5=Optimised)
                    </div>
                    <div style={{ display: 'flex', gap: '0.8rem', justifyContent: 'flex-end', marginTop: '0.8rem', flexWrap: 'wrap' }}>
                      {[['#64748b','1-Adhoc'],['#b45309','2-Repeatable'],['#1d4ed8','3-Defined'],['#5b2d90','4-Managed'],['#0f766e','5-Optimised']].map(([c, l]) => (
                        <div key={l} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                          <div style={{ width: 14, height: 14, borderRadius: 3, background: c }} />
                          <span style={{ fontSize: '0.72rem', fontWeight: 600, color: '#555' }}>{l}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })()}
            </div>
          )}

          <div className="gauges-row">
            {Object.entries(results.domain_scores || {}).map(([d, s]) => {
              const num = typeof s === 'number' ? s : parseFloat(s) || 0;
              return <MaturityGauge key={d} score={num} label={d} />;
            })}
          </div>

          <SectionHeader>📥 Download Reports</SectionHeader>
          <div className="download-row">
            <div className="download-card">
              <div className="dl-icon">📄</div>
              <div className="dl-title">PDF Maturity Report</div>
              <div className="dl-desc">Executive maturity summary slide, domain scoring, and detailed question-level scoring.</div>
              <a href={downloadMaturityPDF(sessionId)} className="btn-primary" download>⬇ Download PDF</a>
            </div>
            <div className="download-card">
              <div className="dl-icon">📊</div>
              <div className="dl-title">Excel Workbook</div>
              <div className="dl-desc">Multi-sheet: dimension summary, overall maturity, question responses, exception sheets.</div>
              <a href={downloadMaturityExcel(sessionId)} className="btn-primary" download>⬇ Download Excel</a>
            </div>
          </div>

          <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
            <button className="btn-secondary" onClick={() => { setSubmitted(false); setResults(null); }}>✏️ Edit Responses</button>
          </div>
        </div>
      )}

      {/* ════════ FORM ════════ */}
      {!submitted && !loading && (
        <div className="maturity-form">

          {/* Sidebar */}
          <div className="mat-sidebar">
            <div className="sidebar-section">
              <h4>⚙️ Configuration</h4>
              <label className="form-label">Client Name <span className="required">*</span>
                <input type="text" value={clientName} onChange={e => setClientName(e.target.value)} placeholder="Organisation name (required)" />
              </label>
              {!clientName.trim() && <p className="field-error">⚠ Required</p>}
            </div>

            <div className="sidebar-section">
              <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '2px solid #b09dd6',
                borderRadius: 12, padding: '0.65rem 0.8rem', boxShadow: '0 2px 10px rgba(91,45,144,0.12)' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.25rem' }}>
                  <span style={{ fontSize: '1.1rem' }}>📋</span>
                  <span style={{ fontSize: '0.88rem', fontWeight: 800, color: '#3b1f72' }}>Masters Applicable</span>
                </div>
                <p style={{ fontSize: '0.76rem', color: '#5b2d90', margin: '0 0 0.4rem', lineHeight: 1.4 }}>
                  Enable to evaluate maturity per Master Data Object
                </p>
                <label className="checkbox-label" style={{ marginBottom: 0 }}>
                  <input type="checkbox" checked={mastersApplicable} onChange={e => setMastersApplicable(e.target.checked)} />
                  Include Master Data Objects in assessment
                </label>
              </div>
            </div>

            {mastersApplicable && (
              <div className="sidebar-section">
                <label className="form-label">Master Data Objects
                  <select multiple value={objects} onChange={e => setObjects(Array.from(e.target.selectedOptions, o => o.value))} style={{ height: 140 }}>
                    {DEFAULT_OBJECTS.map(o => <option key={o}>{o}</option>)}
                  </select>
                </label>
              </div>
            )}

            <div className="sidebar-section">
              <label className="form-label">Maturity Dimensions</label>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {DIMS_LIST.map(d => (
                  <span key={d} style={{ background: '#5b2d90', color: '#fff', fontSize: '0.7rem', fontWeight: 700, padding: '3px 8px', borderRadius: 999 }}>{d} ✕</span>
                ))}
              </div>
            </div>

            <div className="sidebar-section">
              <label className="form-label">Industry Benchmark
                <input type="number" min="1" max="5" step="0.1" value={benchmark} onChange={e => setBenchmark(parseFloat(e.target.value) || 3)} />
              </label>
              <label className="form-label">Target Score
                <input type="number" min="1" max="5" step="0.1" value={target} onChange={e => setTarget(parseFloat(e.target.value) || 3)} />
              </label>
              <label className="form-label">Exception Threshold (≤)
                <input type="range" min="1" max="5" step="0.5" value={lowThr} onChange={e => setLowThr(parseFloat(e.target.value))} />
                <span className="range-val">{lowThr}</span>
              </label>
            </div>

            <div style={{ fontSize: '0.72rem', padding: '0.35rem 0.5rem', borderRadius: 8, textAlign: 'center', marginTop: 4,
              border: '1px solid', borderColor: apiStatus === 'connected' ? '#bbf7d0' : '#fde68a',
              background: apiStatus === 'connected' ? '#f0fdf4' : '#fffbeb',
              color: apiStatus === 'connected' ? '#059669' : '#d97706' }}>
              {apiStatus === 'connected' ? '🟢 Backend connected' : '🟡 Offline mode'}
            </div>
          </div>

          {/* Main */}
          <div className="mat-main">
            <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '1.5px solid #d9cef0',
              borderRadius: 14, padding: '1rem 1.4rem 0.8rem', marginBottom: '1rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginBottom: '0.3rem' }}>
                <span style={{ fontSize: '1.3rem' }}>✏️</span>
                <span style={{ fontSize: '1rem', fontWeight: 800, color: '#3b1f72' }}>Assessment Entry</span>
              </div>
              <p style={{ fontSize: '0.85rem', color: '#5b2d90', margin: 0, lineHeight: 1.5 }}>
                Rate each question per Master Data Object using the dropdown selectors in the grid below,
                or use <strong>Upload Template</strong> to fill offline and import responses.
              </p>
            </div>

            <div className="tab-bar">
              <button className={`tab-btn ${entryTab === 'manual' ? 'active' : ''}`} onClick={() => setEntryTab('manual')}>✏️ Manual Entry</button>
              <button className={`tab-btn ${entryTab === 'upload' ? 'active' : ''}`} onClick={() => setEntryTab('upload')}>📤 Upload Template</button>
            </div>

            {entryTab === 'manual' && (
              <>
                <div className="tab-bar" style={{ marginTop: 0, borderBottom: '2px solid #d9cef0' }}>
                  {DIMS_LIST.map(d => {
                    const { filled, total } = countFilled(d);
                    return (
                      <button key={d} className={`tab-btn ${activeDim === d ? 'active' : ''}`}
                        onClick={() => setActiveDim(d)} style={{ fontSize: '0.82rem' }}>
                        {d}
                        <span style={{ marginLeft: 5, fontSize: '0.65rem', fontWeight: 700,
                          background: filled > 0 ? '#5b2d90' : '#e8e2f5',
                          color: filled > 0 ? '#fff' : '#7a7a9a', borderRadius: 999, padding: '1px 5px' }}>
                          {filled}/{total}
                        </span>
                      </button>
                    );
                  })}
                </div>

                <div style={{ display: 'flex', gap: '0.5rem', margin: '0.6rem 0' }}>
                  {[
                    ['➕ Add Question', () => addQuestion(activeDim)],
                    ['➖ Remove Last',  () => removeLast(activeDim)],
                    [fullView[activeDim] ? '◱ Compact' : '⛶ Full View',
                      () => setFullView(p => ({ ...p, [activeDim]: !p[activeDim] }))],
                  ].map(([label, fn]) => (
                    <button key={label} onClick={fn} style={{ flex: 1, padding: '0.45rem 0.8rem',
                      border: '1.5px solid #d9cef0', borderRadius: 8, background: '#fff',
                      color: '#3b1f72', fontWeight: 600, fontSize: '0.82rem', cursor: 'pointer' }}>
                      {label}
                    </button>
                  ))}
                </div>

                <EditableGrid
                  rows={gridData[activeDim] || []}
                  objects={currentObjects}
                  onChange={(ri, obj, val) => handleCellChange(activeDim, ri, obj, val)}
                  fullView={!!fullView[activeDim]}
                />
              </>
            )}

            {entryTab === 'upload' && (
              <UploadTemplateTab
                objects={currentObjects}
                gridData={gridData}
                onGridImported={handleGridImported}
              />
            )}

            <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '1.5px solid #d9cef0',
              borderRadius: 10, padding: '0.6rem 1rem', margin: '0.8rem 0', fontSize: '0.82rem', color: '#3b1f72' }}>
              <strong>Overall progress:</strong> {tp.filled} / {tp.total} cells rated
              ({tp.total > 0 ? Math.round(tp.filled / tp.total * 100) : 0}%)
              <div style={{ marginTop: 4, height: 6, background: '#e8e2f5', borderRadius: 999, overflow: 'hidden' }}>
                <div style={{ width: `${tp.total > 0 ? (tp.filled / tp.total * 100) : 0}%`, height: '100%',
                  borderRadius: 999, background: 'linear-gradient(90deg,#5b2d90,#b10f74)', transition: 'width 0.3s' }} />
              </div>
            </div>

            <div className="submit-section">
              <button className="btn-run" onClick={handleSubmit} disabled={!clientName.trim() || loading}>
                ✅ Submit &amp; Generate Report
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}
